arguments.new_str:
class EnvVarCheck
{
    void CheckFlag()
    {
        // .NET 9 breaking change: empty environment variables are now supported
        // and no longer treated as unset. In .NET 8, export MY_FLAG="" returned
        // null from GetEnvironmentVariable; in .NET 9 it returns "".
        // Use 'is null' (not IsNullOrEmpty) to correctly distinguish
        // "not set" (null) from "explicitly empty" ("").
        var val = Environment.GetEnvironmentVariable("MY_FLAG");
        if (val is null)
        {
            Console.WriteLine("MY_FLAG not set, using default");
        }
        else if (val.Length == 0)
        {
            Console.WriteLine("MY_FLAG explicitly set to empty");
        }
    }
}

